// Pull candidate profile (first row of the Candidate Profile sheet)
const profile = $('Load Candidate Profile').first().json || {};
const candidate = {
  skills: profile.skills || '',
  salary_expectation: profile.salary_expectation || '',
  preferred_industries: profile.preferred_industries || ''
};

// Decodo wraps the scraped payload. Adjust the path to match YOUR target's response.
// Common shapes handled below: { results:[{content:[...] }] } or a raw array.
const raw = $input.first().json;
let jobs = [];
try {
  if (Array.isArray(raw)) jobs = raw;
  else if (raw.results && raw.results[0] && Array.isArray(raw.results[0].content)) jobs = raw.results[0].content;
  else if (Array.isArray(raw.content)) jobs = raw.content;
  else if (Array.isArray(raw.jobs)) jobs = raw.jobs;
  else if (raw.data && Array.isArray(raw.data)) jobs = raw.data;
} catch (e) { jobs = []; }

// Build one n8n item per job, with a ready-to-score prompt string.
return jobs
  .filter(j => j && (j.position || j.title))
  .slice(0, 25) // safety cap so a daily run stays fast
  .map(j => {
    const title = j.position || j.title || '';
    const company = j.company || j.company_name || '';
    const description = (j.description || j.snippet || '').toString().slice(0, 4000);
    const url = j.url || j.apply_url || j.link || '';
    const location = j.location || 'Remote';
    const salary = j.salary || j.salary_max || '';
    const prompt = `CANDIDATE PROFILE:\nSkills: ${candidate.skills}\nSalary expectation: ${candidate.salary_expectation}\nPreferred industries: ${candidate.preferred_industries}\n\nJOB POSTING:\nTitle: ${title}\nCompany: ${company}\nLocation: ${location}\nSalary: ${salary}\nDescription: ${description}\n\nScore this job for this candidate and return JSON only.`;
    return { json: { job_title: title, company, job_url: url, location, prompt } };
  });

// The LLM text output
let text = ($json.text || $json.response || '').toString().trim();

// Strip code fences if the model added them
text = text.replace(/^```(json)?/i, '').replace(/```$/,'').trim();

// Grab the first {...} block to be safe
const match = text.match(/\{[\s\S]*\}/);
let parsed = {};
try { parsed = JSON.parse(match ? match[0] : text); } catch (e) { parsed = {}; }

// Carry through the original job url/location from the paired Prepare Jobs item
const src = $('Prepare Jobs').item.json;

return {
  json: {
    job_title: parsed.job_title || src.job_title || '',
    company: parsed.company || src.company || '',
    fit_score: Number(parsed.fit_score) || 0,
    matched_skills: Array.isArray(parsed.matched_skills) ? parsed.matched_skills.join(', ') : '',
    missing_skills: Array.isArray(parsed.missing_skills) ? parsed.missing_skills.join(', ') : '',
    reason: parsed.reason || '',
    recommendation: parsed.recommendation || '',
    job_url: src.job_url || '',
    location: src.location || '',
    scored_at: new Date().toISOString()
  }
};
